  const EROS_NOVEL_PRE_PROMPTS = decodeErosPrePrompts(EROS_NOVEL_PRE_PROMPTS_B64);

  function decodeErosPromptBase64Utf8(value) {
    const text = String(value || '').trim();
    if (!text) return '{}';
    if (typeof Buffer !== 'undefined') return Buffer.from(text, 'base64').toString('utf8');
    if (typeof TextDecoder !== 'undefined' && typeof atob === 'function') {
      const binary = atob(text);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
      return new TextDecoder('utf-8').decode(bytes);
    }
    if (typeof atob === 'function') {
      const binary = atob(text);
      return decodeURIComponent(Array.from(binary, ch => `%${ch.charCodeAt(0).toString(16).padStart(2, '0')}`).join(''));
    }
    throw new Error('No base64 decoder available');
  }

  function decodeErosPrePrompts(value) {
    try {
      const parsed = JSON.parse(decodeErosPromptBase64Utf8(value));
      return parsed && typeof parsed === 'object' ? parsed : {};
    } catch (_) {
      return {};
    }
  }

