    if (/^(?:[-*_~=`#>|:\s]|·|•|─|━|—)+$/.test(text)) return false;
    const compact = text.replace(/[#*_~=`>|:\-—–·•─━\s.,，。;；!?！？()[\]{}"'“”‘’「」『』《》]+/g, '');
