            loadState = original.loadState;
            mountGameplayComposerPanel = original.mountGameplayComposerPanel;
            unmountGameplayComposerPanel = original.unmountGameplayComposerPanel;
            reconcileGameplayLauncherForPanelState = original.reconcileGameplayLauncherForPanelState;
            prepareSelectedGameplayActor = original.prepareSelectedGameplayActor;
