        testStorageDictionaryCodec: () => {
          const sample = `${STORAGE_DICTIONARY.join('value\n')}value\n한국어 日本語 中文 English\n${'state '.repeat(120)}`;
          let legacy = sample;
          STORAGE_DICTIONARY.forEach((token, idx) => {
            legacy = legacy.split(token).join(String.fromCharCode(0xe000 + idx));
          });
          const encoded = compressTextDictionary(sample);
          return {
            sameEncodingAsLegacy: encoded === legacy,
            roundTrip: decompressTextDictionary(encoded) === sample,
            sourceLength: sample.length,
            encodedLength: encoded.length,
          };
        },
        testStorageLzwCodec: () => {
          const sample = Array.from({ length: 320 }, (_, index) => JSON.stringify({
            id: `기억-${index}`,
            summary: `한국어 장기기억 ${index % 17} · 日本語の記憶 · 中文记忆 · English memory`,
            evidence: ['같은 세계관과 관계가 반복되어도 원문은 정확히 복원되어야 한다.'],
          })).join('\n');
          const encoded = compressTextLzw(sample);
          const decoded = decompressTextLzw(encoded);
          return {
            multilingualRoundTrip: decoded === sample,
            checksumStable: hashString(decoded) === hashString(sample),
            materiallySmaller: utf8ByteLength(encoded) < utf8ByteLength(sample) * 0.7,
            sourceBytes: utf8ByteLength(sample),
            encodedBytes: utf8ByteLength(encoded),
          };
        },
        testStorageLzwLargeUnicodeRoundTrip: () => {
          let seed = 0x9e3779b9;
          const chunks = [];
          for (let index = 0; index < 120000; index += 1) {
            seed ^= seed << 13;
            seed ^= seed >>> 17;
            seed ^= seed << 5;
            seed >>>= 0;
            chunks.push(String.fromCharCode(32 + seed % 95));
            if (index % 113 === 0) chunks.push('한글🙂日本語·中文');
          }
          const source = chunks.join('');
          const encoded = compressTextLzw(source);
          const decoded = decompressTextLzw(encoded);
          return {
            largeMultilingualRoundTrip: decoded === source,
            checksumStable: hashString(decoded) === hashString(source),
            crossesLargeDictionaryScale: utf8ByteLength(source) > 65535,
          };
        },
