  async function clearGameplayComposerListeners(expectedSession = null) {
    if (expectedSession && Runtime.gameplayComposerListenerSession
      && Runtime.gameplayComposerListenerSession !== expectedSession) {
      return { removed: 0, stale: true };
    }
    const root = Runtime.gameplayComposerListenerRoot;
    const listeners = Array.isArray(Runtime.gameplayComposerListenerIds)
      ? Runtime.gameplayComposerListenerIds.slice()
      : [];
    // Detach the published batch before awaiting removals. A newer bind can now
    // publish its own batch without an older cleanup erasing those handles.
    Runtime.gameplayComposerListenerRoot = null;
    Runtime.gameplayComposerListenerIds = [];
    Runtime.gameplayComposerListenerSession = null;
    const liveBinding = Runtime.gameplayComposerLiveBinding;
    if (!expectedSession || !liveBinding?.session || liveBinding.session === expectedSession) {
      Runtime.gameplayComposerLiveBinding = null;
      if (liveBinding) liveBinding.measureEpoch = Math.max(0, Number(liveBinding.measureEpoch || 0)) + 1;
    }
    await Promise.all(listeners.map(async item => {
      try { await root?.removeEventListener?.(item.type, item.id); } catch (_) {}
    }));
    return { removed: listeners.length };
  }

  function gameplayComposerButtonId(index) {
    return `${UI_ID_IN_CHAT_PANEL}-control-${index}`;
  }

  function gameplayComposerSurfaceId() {
    return `${UI_ID_IN_CHAT_PANEL}-surface`;
  }

  function gameplayComposerIndexedControls(viewModel) {
    return (viewModel?.controls || []).map((control, index) => ({ ...control, id: gameplayComposerButtonId(index) }));
  }

  function gameplayComposerControlKey(control) {
    return [
      cleanString(control?.slot, ''),
      cleanString(control?.command, ''),
      cleanString(control?.value, ''),
    ].join('\u001f');
  }

  function gameplayComposerPanelInnerHtml(html) {
    const source = String(html || '');
    const openIndex = source.indexOf('>');
    const closeIndex = source.lastIndexOf('</div>');
    return openIndex >= 0 && closeIndex > openIndex
      ? source.slice(openIndex + 1, closeIndex)
      : '';
  }

  function recordGameplayComposerPerformance(kind, startedAt, details = {}) {
    const entry = {
      kind: cleanString(kind, 'unknown'),
      durationMs: Math.max(0, Date.now() - Number(startedAt || Date.now())),
      at: nowIso(),
      ...(details && typeof details === 'object' ? details : {}),
    };
    const trace = Array.isArray(Runtime.gameplayComposerPerformanceTrace)
      ? Runtime.gameplayComposerPerformanceTrace
      : [];
    trace.push(entry);
    Runtime.gameplayComposerPerformanceTrace = trace.slice(-24);
    if (entry.durationMs >= 750 && typeof console !== 'undefined' && typeof console.info === 'function') {
      console.info('[Eros Tower] gameplay panel timing', entry);
    }
    return entry;
  }

  function gameplayCustomActionInputId() {
    return `${UI_ID_IN_CHAT_PANEL}-custom-action-input`;
  }

  function gameplayInstructionsInputId() {
    return `${UI_ID_IN_CHAT_PANEL}-gameplay-instructions-input`;
  }

  function setGameplayInstructionsDraft(value, session = Runtime.gameplayComposerPanelSession) {
    Runtime.gameplayInstructionsDraft = normalizeGameplayCustomInstructions(value);
    Runtime.gameplayInstructionsDraftSession = session || null;
    return Runtime.gameplayInstructionsDraft;
  }

  function clearGameplayInstructionsDraft() {
    Runtime.gameplayInstructionsDraft = '';
    Runtime.gameplayInstructionsDraftSession = null;
  }

  async function captureGameplayInstructionsDraftFromDom(session = Runtime.gameplayComposerPanelSession) {
    if (Runtime.gameplayInstructionsEditorOpen !== true
      || !session || Runtime.gameplayInstructionsDraftSession !== session) return false;
    try {
      const root = await api.getRootDocument();
      const input = await root?.getElementById?.(gameplayInstructionsInputId());
      if (!input) return false;
      const liveText = await input.innerText?.();
      if (typeof liveText !== 'string') return false;
      setGameplayInstructionsDraft(liveText, session);
      return true;
    } catch (_) {
      return false;
    }
  }

  function promptGameplayActorName(language = 'ko') {
    if (Runtime.gameplayActorInputOpen) return null;
    if (typeof globalThis.prompt !== 'function') throw new Error(gameplayUiText(language, 'actorInputUnavailable'));
    Runtime.gameplayActorInputOpen = true;
    try {
      const value = globalThis.prompt(gameplayUiText(language, 'actorInputPrompt'), '');
      return value === null ? null : String(value);
    } finally {
      Runtime.gameplayActorInputOpen = false;
    }
  }

  function promptGameplayText(language, promptKey, initialValue = '') {
    if (Runtime.gameplayTextInputOpen) return null;
    if (typeof globalThis.prompt !== 'function') throw new Error(gameplayUiText(language, 'textInputUnavailable'));
    Runtime.gameplayTextInputOpen = true;
    try {
      const value = globalThis.prompt(gameplayUiText(language, promptKey), String(initialValue || ''));
      return value === null ? null : String(value);
    } finally {
      Runtime.gameplayTextInputOpen = false;
    }
  }

  function gameplayComposerTab(value) {
    const normalized = cleanString(value, '').slice(0, 80);
    if (['context', 'ability', 'item'].includes(normalized)) return normalized;
    return /^(?:ability|item)-category-[a-z0-9]+$/.test(normalized) ? normalized : '';
  }

  function gameplayInventoryPageSize() {
    return GAMEPLAY_INVENTORY_PAGE_SIZE;
  }

  function gameplayAdvisorOutputLanguage(conf = null) {
    return normalizeGameplayOutputLanguage(getGameplayAdvisorAgent(conf)?.outputLanguage);
  }

