    const customActionBanner = viewModel?.customAction ? `<div data-gameplay-custom-action style="display:flex;align-items:center;justify-content:space-between;gap:7px;margin:6px 0;padding:6px 7px;border:1px solid #5e5364;border-radius:8px;background:#29242d"><div style="min-width:0"><span style="display:block;font-size:8px;color:#a99caf">${escHtml(ui('userDirective'))}</span><strong style="display:block;margin-top:1px;font-size:10px;color:#ddd2e1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(viewModel.customAction.request)}</strong></div>${compactButton(one('custom-action-clear'),'×',`aria-label="${escHtml(ui('releaseDirective'))}" title="${escHtml(ui('releaseInstruction'))}"`,24)}</div>` : '';
